<template>
  <v-card fill-height class="overflow-hidden icardTop rounded-0">
    <v-card-text class="pa-0 py-1 d-block">
      <slot name="body">
        {{}}
      </slot>
    </v-card-text>
    <i-button-list
      :useBtnList="useBtnList"
      :reportItems="reportItems"
      @btnClick="clickButton"
      class="d-block py-3 pr-2 pl-1 pl-md-0 btn_list"
      style="float:right;"
    />
  </v-card>
</template>

<script>
import iButtonList from './iButtonList.vue'

export default {
  name: 'i-card-top',
  components: {
    iButtonList
  },
  props: {
    headerTitle: {
      type: String,
      default: '제목'
    },
    color: {
      type: String,
      default: 'card_bg'
    },
    divider: {
      type: Boolean,
      default: false
    },
    // 버튼 리스트
    useBtnList: {
      type: Array,
      default: () => ['']
    },
    reportItems: {
      type: Array,
      default: () => [
        { role: 'pptx', title: 'PPT' },
        { role: 'pdf', title: 'PDF' },
        { role: 'docx', title: 'DOCX' },
        // { role: 'html', title: 'WEB'},
        { role: 'xls', title: 'EXCEL' }
      ]
    }
  },
  methods: {
    // 버튼 클릭 시 각 id별로 이벤트생성
    clickButton(targetButton) {
      this.$emit(targetButton.id, targetButton.role)
    }
  }
}
</script>

<style lang="scss" scoped>
.v-card {
  // background: #ecedf3;
  // background-color: #f1f3fe;
  background-color: #ffffff00;
  margin-bottom: 22px;
}
</style>
